import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import axios from 'axios';
import { Helmet } from 'react-helmet-async';
import Skeleton from 'react-loading-skeleton';
import toast from 'react-hot-toast';
import { apiMessage } from '../lib/api';

export default function Orders({ embedded }) {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    let cancelled = false;
    (async () => {
      try {
        const res = await axios.get('/api/orders/my-orders', { withCredentials: true });
        const d = res.data?.data;
        if (!cancelled) setData(d);
      } catch (e) {
        if (!cancelled) {
          toast.error(apiMessage(e, 'Could not load orders'));
          setData(null);
        }
      } finally {
        if (!cancelled) setLoading(false);
      }
    })();
    return () => {
      cancelled = true;
    };
  }, []);

  const orders = data?.orders || [];

  const body = (
    <>
      {loading ? (
        <Skeleton count={6} />
      ) : orders.length === 0 ? (
        <p className="empty-products-hint">
          You have no orders yet.{' '}
          <Link to="/shop" className="btn btn-primary btn-sm">
            Start shopping
          </Link>
        </p>
      ) : (
        <ul className="orders-list">
          {orders.map((order) => (
            <li key={order._id} className="order-card card-like">
              <div className="order-card__head">
                <span className="order-id">Order #{String(order._id).slice(-8)}</span>
                <span className={`order-status order-status--${order.status}`}>{order.status}</span>
              </div>
              <div className="order-card__meta">
                <span>{new Date(order.createdAt).toLocaleDateString()}</span>
                <span className="order-total">£{Number(order.totalPrice).toFixed(2)}</span>
              </div>
              <ul className="order-lines">
                {(order.orderItems || []).map((line, i) => (
                  <li key={i}>
                    {line.name} × {line.quantity}
                  </li>
                ))}
              </ul>
            </li>
          ))}
        </ul>
      )}
    </>
  );

  if (embedded) {
    return (
      <>
        <Helmet>
          <title>My orders | Nova Shop</title>
        </Helmet>
        <h2 style={{ fontSize: '1.25rem', marginBottom: '1rem' }}>Orders</h2>
        {body}
      </>
    );
  }

  return (
    <main className="section orders-page">
      <Helmet>
        <title>My orders | Nova Shop</title>
      </Helmet>
      <div className="container">
        <header className="page-header">
          <h1>My orders</h1>
          <ol className="breadcrumb">
            <li>
              <Link to="/">Home</Link>
            </li>
            <li className="active">Orders</li>
          </ol>
        </header>
        {body}
      </div>
    </main>
  );
}
